package ir.tahamohamadi.resume.api.publicsite;
import ir.tahamohamadi.common.domain.*; import ir.tahamohamadi.resume.*; import org.springframework.data.domain.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.time.*; import java.util.*;
@Service @Transactional(readOnly=true) public class PublicResumeService {private final ResumeEntryTranslationRepository entries;private final ResumeDocumentRepository documents;public PublicResumeService(ResumeEntryTranslationRepository entries,ResumeDocumentRepository documents){this.entries=entries;this.documents=documents;}public PublicResumeResponse get(LanguageCode locale){List<PublicResumeEntryResponse> values=entries.findPublishedByLanguage(locale,PageRequest.of(0,50,Sort.by(Sort.Order.asc("entry.sortOrder"),Sort.Order.desc("entry.startedOn"),Sort.Order.asc("entry.id")))).map(this::entry).getContent();PublicResumeDocumentResponse doc=documents.findByLanguageCodeAndStatusAndDeletedAtIsNull(locale,ContentStatus.PUBLISHED).map(this::document).orElse(null);return new PublicResumeResponse(locale,values,doc,List.of("fa","en"));}private PublicResumeEntryResponse entry(ResumeEntryTranslation t){ResumeEntry e=t.getEntry();return new PublicResumeEntryResponse(t.getTitle(),t.getOrganization(),t.getLocation(),t.getSummary(),e.getEntryType(),e.getStartedOn(),e.getEndedOn(),e.isCurrent());}private PublicResumeDocumentResponse document(ResumeDocument d){return new PublicResumeDocumentResponse(d.getId(),"/api/v1/public/media/"+d.getMediaAsset().getId(),d.getPublishedAt());}}
record PublicResumeResponse(LanguageCode locale,List<PublicResumeEntryResponse> entries,PublicResumeDocumentResponse document,List<String> availableLocales) { }
record PublicResumeEntryResponse(String title,String organization,String location,String summary,ResumeEntryType entryType,LocalDate startedOn,LocalDate endedOn,boolean current) { }
record PublicResumeDocumentResponse(UUID id,String mediaUrl,Instant publishedAt) { }
